class LUPrefix {
public:
    LUPrefix(int n) {
        prefix_lengths.resize(n + 1, 0);
    }

    void upload(int video) {
        prefix_lengths[video]++;
    }

    int longest() {
        int max_length = 0;
        for (int i = 1; i <= n; i++) {
            max_length = max(max_length, prefix_lengths[i]);
        }
        return max_length;
    }

private:
    vector<int> prefix_lengths;
};
```

